import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../hooks/usecart';
import { ChevronLeft, AlertTriangle, Check, Loader2 } from 'lucide-react';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items = [] } = useCart();

  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  useEffect(() => {
    if (validItems.length === 0) {
      navigate('/cart');
    }
  }, [validItems, navigate]);

  // ========================================================
  // FORM STATES
  // ========================================================
  const [isBillingSame, setIsBillingSame] = useState(true);

  const [shipping, setShipping] = useState({
    fullName: '', phone: '', address1: '', address2: '', pincode: '', city: '', state: ''
  });

  const [billing, setBilling] = useState({
    fullName: '', email: '', phone: '', pincode: '', city: '', state: '', address1: '', address2: '', landmark: ''
  });

  // Validation Modal State
  const [errors, setErrors] = useState({});
  const [showModal, setShowModal] = useState(false);
  const [modalMessage, setModalMessage] = useState('');

  const [fetchingPin, setFetchingPin] = useState({ shipping: false, billing: false });

  // ========================================================
  // API: AUTO-FETCH PINCODE
  // ========================================================
  const fetchLocation = async (pin, type) => {
    if (pin.length !== 6) return;
    setFetchingPin(prev => ({ ...prev, [type]: true }));

    try {
      const response = await fetch(`https://api.postalpincode.in/pincode/${pin}`);
      const data = await response.json();

      if (data && data[0] && data[0].Status === 'Success' && data[0].PostOffice?.length > 0) {
        const po = data[0].PostOffice[0];
        const fetchedCity = po.District || po.Block || po.Region || '';
        const fetchedState = po.State || '';

        if (type === 'shipping') {
          setShipping(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        } else {
          setBilling(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        }
        setErrors(prev => ({ ...prev, [`shipping_city`]: false, [`shipping_state`]: false, [`shipping_pincode`]: false }));
      }
    } catch (error) {
      console.error("Error fetching pincode:", error);
    } finally {
      setFetchingPin(prev => ({ ...prev, [type]: false }));
    }
  };

  useEffect(() => {
    const pin = shipping.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'shipping'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [shipping.pincode]);

  useEffect(() => {
    const pin = billing.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'billing'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [billing.pincode]);

  // ========================================================
  // MATH CALCULATIONS
  // ========================================================
  const totalItems = validItems.reduce((acc, item) => acc + (Number(item.quantity) || 1), 0);

  let totalDiscountedPrice = 0;
  let totalMrp = 0;

  validItems.forEach(item => {
    const qty = Number(item.quantity) || 1;
    const price = Number(item.price) || 0;
    const mrp = Number(item.compare_price || item.mrp) || Math.round(price * 1.25);
    totalDiscountedPrice += (price * qty);
    totalMrp += (mrp * qty);
  });

  const baseDiscount = Math.max(0, totalMrp - totalDiscountedPrice);
  const couponDiscount = 10750;
  const finalPayable = Math.max(0, totalDiscountedPrice - couponDiscount);
  const totalSaved = baseDiscount + couponDiscount;

  // Handlers
  const handleShippingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setShipping(prev => ({ ...prev, [name]: value }));
    if (errors[`shipping_${name}`]) setErrors(prev => ({ ...prev, [`shipping_${name}`]: false }));
  };

  const handleBillingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setBilling(prev => ({ ...prev, [name]: value }));
    if (errors[`billing_${name}`]) setErrors(prev => ({ ...prev, [`billing_${name}`]: false }));
  };

  const handleContinuePayment = () => {
    let hasError = false;
    const newErrors = {};

    const reqShipping = ['fullName', 'phone', 'address1', 'pincode', 'city', 'state'];
    reqShipping.forEach(field => {
      if (!shipping[field].trim()) { newErrors[`shipping_${field}`] = true; hasError = true; }
    });

    if (shipping.phone && shipping.phone.replace(/\D/g, '').length < 10) {
      newErrors.shipping_phone = true; hasError = true;
    }
    if (shipping.pincode && shipping.pincode.replace(/\D/g, '').length !== 6) {
      newErrors.shipping_pincode = true; hasError = true;
    }

    if (hasError) {
      setErrors(newErrors);
      setModalMessage('Please fill in all required shipping details to proceed with your order.');
      setShowModal(true);
      return;
    }

    console.log("Proceeding to payment:", { shipping, billing: isBillingSame ? shipping : billing });
    alert("Validation Passed! Proceeding to Payment Gateway.");
  };

  // ========================================================
  // CLEAN INPUT CLASS (No Ghost Lines, Exact Match)
  // ========================================================
  const getInputClass = (isError) => `
    w-full text-[14px] rounded-lg px-4 py-3 outline-none focus:outline-none focus-visible:outline-none ring-0 focus:ring-0 focus-visible:ring-0 transition-colors placeholder:text-gray-400 bg-clip-padding
    ${isError
      ? 'bg-[#fef2f2] border border-red-400 text-gray-900'
      : 'bg-white border border-gray-200 focus:border-[#f97316] hover:border-gray-300 text-gray-900'
    }
  `;

  return (
    <div className="bg-[#f8f9fa] min-h-screen py-6 md:py-10 font-sans relative">

      {/* MODAL */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-[90vw] sm:max-w-sm p-6 sm:p-8 transform transition-all flex flex-col items-center text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-[#fef2f2] text-red-500 rounded-full flex items-center justify-center mb-5">
              <AlertTriangle size={28} strokeWidth={1.5} />
            </div>
            <h3 className="text-[18px] sm:text-[20px] font-bold text-gray-900 mb-2 tracking-tight">Missing Information</h3>
            <p className="text-[13px] sm:text-[14px] text-gray-500 mb-8 leading-relaxed px-2">
              {modalMessage}
            </p>
            <button
              onClick={() => setShowModal(false)}
              className="w-full bg-gray-900 text-white font-bold py-3.5 rounded-xl hover:bg-gray-800 hover:shadow-lg hover:shadow-gray-900/20 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none focus-visible:outline-none focus:ring-0 border-0 select-none"
              style={{ WebkitTapHighlightColor: 'transparent' }}
            >
              GOT IT
            </button>
          </div>
        </div>
      )}

      <div className="container mx-auto px-4 max-w-6xl">
        <div className="mb-4 md:mb-6">
          <button
            onClick={() => navigate('/cart')}
            className="inline-flex items-center text-sm font-bold text-[#f97316] hover:text-orange-600 transition-colors group outline-none focus:outline-none focus-visible:outline-none focus:ring-0 border-none bg-transparent select-none"
            style={{ WebkitTapHighlightColor: 'transparent' }}
          >
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            Return to Cart
          </button>
        </div>

        <div className="flex items-center mb-6 md:mb-8">
          <h1 className="text-[24px] md:text-[28px] font-black text-[#1e293b] tracking-tight">Checkout</h1>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 items-start">

          {/* LEFT COLUMN: FORMS */}
          <div className="lg:col-span-7 flex flex-col gap-6">

            {/* SHIPPING ADDRESS */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-5 md:p-8">

              <div className="flex items-center gap-3 mb-6 md:mb-8">
                <div className="bg-[#f97316] text-white w-8 h-8 flex items-center justify-center rounded-full shadow-sm shrink-0">
                  <span className="font-bold text-sm">1</span>
                </div>
                <h2 className="text-[16px] md:text-[18px] font-bold text-[#1e293b]">Shipping Address</h2>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-5 gap-y-5 md:gap-y-6">
                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Full Name *</label>
                  <input type="text" name="fullName" value={shipping.fullName} onChange={handleShippingChange} className={getInputClass(errors.shipping_fullName)} placeholder="e.g. John Doe" />
                </div>

                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Phone Number *</label>
                  <input type="tel" name="phone" value={shipping.phone} onChange={handleShippingChange} maxLength="10" className={getInputClass(errors.shipping_phone)} placeholder="e.g. 9876543210" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 1 *</label>
                  <input type="text" name="address1" value={shipping.address1} onChange={handleShippingChange} className={getInputClass(errors.shipping_address1)} placeholder="House No., Building Name, Street" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 2 (Optional)</label>
                  <input type="text" name="address2" value={shipping.address2} onChange={handleShippingChange} className={getInputClass(false)} placeholder="Locality, Area, Landmark" />
                </div>

                <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-5">
                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">City *</label>
                    <input type="text" name="city" value={shipping.city} onChange={handleShippingChange} className={getInputClass(errors.shipping_city)} placeholder="City" />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">State *</label>
                    <input type="text" name="state" value={shipping.state} onChange={handleShippingChange} className={getInputClass(errors.shipping_state)} placeholder="State" />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Pincode *</label>
                    <div className="relative">
                      <input type="text" name="pincode" value={shipping.pincode} onChange={handleShippingChange} maxLength="6" className={getInputClass(errors.shipping_pincode)} placeholder="500001" />
                      {fetchingPin.shipping && <div className="absolute right-3 top-1/2 -translate-y-1/2"><Loader2 size={18} className="text-[#f97316] animate-spin" /></div>}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-6 md:mt-8 flex md:justify-start">
                <button
                  onClick={handleContinuePayment}
                  className="w-full md:w-auto bg-[#f97316] text-white px-8 md:px-10 py-3.5 rounded-xl font-bold tracking-wide hover:bg-[#ea580c] hover:shadow-lg hover:shadow-orange-500/30 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none focus:ring-0 select-none border-none text-[14px] md:text-[15px]"
                  style={{ WebkitTapHighlightColor: 'transparent' }}
                >
                  Continue to Payment
                </button>
              </div>
            </div>

            {/* BILLING TOGGLE BOX */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-5 md:p-6">
              <label className="flex items-start md:items-center gap-3 cursor-pointer group w-max outline-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
                <div className={`w-[18px] h-[18px] shrink-0 flex items-center justify-center rounded-[3px] transition-colors mt-0.5 md:mt-0 ${isBillingSame ? 'bg-[#f97316]' : 'bg-white border border-gray-300'}`}>
                  {isBillingSame && <Check size={14} className="text-white" strokeWidth={3} />}
                </div>
                <input
                  type="checkbox"
                  className="hidden"
                  checked={isBillingSame}
                  onChange={() => setIsBillingSame(!isBillingSame)}
                />
                <span className="text-[14px] md:text-[15px] font-medium text-[#1e293b] select-none">Billing address is same as Shipping</span>
              </label>

              {/* EXPANDING BILLING FORM */}
              <div className={`transition-all duration-500 ease-in-out overflow-hidden ${isBillingSame ? 'max-h-0 opacity-0' : 'max-h-[1500px] opacity-100 mt-5 md:mt-6 border-t border-gray-200 pt-5 md:pt-6'}`}>
                <h3 className="text-[15px] md:text-[16px] font-bold text-[#1e293b] mb-5 md:mb-6">Add billing address</h3>

                <div className="flex flex-col gap-4 md:gap-5">
                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Full Name <span className="text-red-500">*</span></label>
                    <input type="text" name="fullName" value={billing.fullName} onChange={handleBillingChange} className={getInputClass(errors.billing_fullName)} placeholder="Name*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Email <span className="text-red-500">*</span></label>
                    <input type="email" name="email" value={billing.email} onChange={handleBillingChange} className={getInputClass(errors.billing_email)} placeholder="Email Address*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Mobile No. <span className="text-red-500">*</span></label>
                    <input type="tel" name="phone" value={billing.phone} onChange={handleBillingChange} maxLength="10" className={getInputClass(errors.billing_phone)} placeholder="Mobile No.*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase mt-2 md:mt-0">Pincode <span className="text-red-500">*</span></label>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 md:gap-4">
                      <div className="relative">
                        <input type="text" name="pincode" value={billing.pincode} onChange={handleBillingChange} maxLength="6" className={getInputClass(errors.billing_pincode)} placeholder="Pin Code*" />
                        {fetchingPin.billing && <div className="absolute right-3 top-1/2 -translate-y-1/2"><Loader2 size={18} className="text-[#f97316] animate-spin" /></div>}
                      </div>
                      <input type="text" name="city" value={billing.city} onChange={handleBillingChange} className={getInputClass(errors.billing_city)} placeholder="City" />
                      <input type="text" name="state" value={billing.state} onChange={handleBillingChange} className={getInputClass(errors.billing_state)} placeholder="State" />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Society Address <span className="text-red-500">*</span></label>
                    <input type="text" name="address1" value={billing.address1} onChange={handleBillingChange} className={getInputClass(errors.billing_address1)} placeholder="Flat, House no., Building, Company*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Area Address <span className="text-red-500">*</span></label>
                    <input type="text" name="address2" value={billing.address2} onChange={handleBillingChange} className={getInputClass(errors.billing_address2)} placeholder="Area, Street, Sector, Village*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-1.5 md:gap-4">
                    <label className="text-[12px] md:text-[13px] font-bold text-gray-600 uppercase">Landmark</label>
                    <input type="text" name="landmark" value={billing.landmark} onChange={handleBillingChange} className={getInputClass(false)} placeholder="Landmark (optional)" />
                  </div>
                </div>
              </div>
            </div>

          </div>

          {/* RIGHT COLUMN: ORDER SUMMARY */}
          {/* Changed md:sticky to lg:sticky so it doesn't break tablet layouts */}
          <div className="lg:col-span-5 flex flex-col gap-6 lg:sticky lg:top-28">
            <div className="bg-white border border-gray-200 shadow-sm overflow-hidden flex flex-col rounded-2xl">

              <div className="p-5 md:p-6 border-b border-gray-100 bg-white">
                <h3 className="text-[16px] md:text-[18px] font-bold text-[#1e293b]">Order Summary</h3>
              </div>

              <div className="p-5 md:p-6 border-b border-gray-100 bg-white flex flex-col gap-5 max-h-[300px] overflow-y-auto custom-scrollbar">
                {validItems.map((item, index) => {
                  const itemQty = Number(item.quantity) || 1;
                  return (
                    <div key={index} className="flex items-start gap-3 md:gap-4">
                      <div className="w-[70px] h-[70px] md:w-[80px] md:h-[80px] bg-gray-50 border border-gray-100 shrink-0 rounded-lg overflow-hidden">
                        <img src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=200&q=80'} alt={item.name} className="w-full h-full object-cover" onError={(e) => { e.target.onerror = null; e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=200&q=80'; }} />
                      </div>
                      <div className="flex-1 min-w-0 pt-1">
                        <h4 className="text-[13px] md:text-[14px] font-semibold text-gray-900 leading-snug mb-1 md:mb-2 truncate">{item.name || 'Premium Item'}</h4>
                        <p className="text-[11px] md:text-[12px] text-gray-500 mb-1">SKU: {item.variantId || item.productId || 'N/A'}</p>
                        <p className="text-[12px] md:text-[13px] text-gray-700 font-medium">Qty: {itemQty}</p>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="p-5 md:p-6 bg-white">
                <h3 className="text-[15px] md:text-[16px] font-bold text-gray-900 mb-4 md:mb-5">Price Detail <span className="text-gray-500 font-normal text-[13px] md:text-[14px]">({totalItems} Items)</span></h3>

                <div className="space-y-3 md:space-y-4">
                  <div className="flex justify-between items-center text-[13px] md:text-[14px] font-medium text-gray-700">
                    <span>MRP</span>
                    <span>₹{totalMrp.toLocaleString('en-IN')}</span>
                  </div>

                  {baseDiscount > 0 && (
                    <div className="flex justify-between items-center text-[13px] md:text-[14px] font-medium text-gray-700">
                      <span>Discount</span>
                      <span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span>
                    </div>
                  )}

                  <div className="flex justify-between items-center text-[13px] md:text-[14px] font-medium text-gray-700">
                    <span>Coupon (SUMMER26)</span>
                    <span className="text-[#22c55e]">- ₹{couponDiscount.toLocaleString('en-IN')}</span>
                  </div>
                </div>

                <div className="mt-5 md:mt-6 pt-5 border-t border-dashed border-gray-200">
                  <div className="flex justify-between items-start">
                    <span className="text-[16px] md:text-[18px] font-bold text-gray-900">Total Payable</span>
                    <div className="text-right">
                      <span className="text-[20px] md:text-[22px] font-black text-gray-900 block mb-1">₹{finalPayable.toLocaleString('en-IN')}</span>
                      <span className="text-[10px] md:text-[11px] font-medium text-gray-500">Inclusive of all taxes</span>
                    </div>
                  </div>
                </div>
              </div>

              {totalSaved > 0 && (
                <div className="p-3.5 md:p-4 bg-[#f0fdf4] border-t border-[#bbf7d0]">
                  <p className="text-[12px] md:text-[13px] font-medium text-[#166534] text-center">
                    Congratulations! You've Just saved ₹{totalSaved.toLocaleString('en-IN')} On Your Order.
                  </p>
                </div>
              )}

            </div>
          </div>

        </div>
      </div>

      <style jsx="true">{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e5e7eb; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #d1d5db; }
      `}</style>
    </div>
  );
};

export default CheckoutPage;
